CREATE DEFINER=`u888578780_bbm`@`127.0.0.1` PROCEDURE `Activate Artist` (IN `p_username` VARCHAR(50))   BEGIN
    DECLARE v_user_id INT;

    /* Get user_id from username */
    SELECT id
    INTO v_user_id
    FROM users
    WHERE username = p_username
    LIMIT 1;

    /* Safety check */
    IF v_user_id IS NULL THEN
        SIGNAL SQLSTATE '45000'
        SET MESSAGE_TEXT = 'User not found';
    END IF;

    START TRANSACTION;

        /* Update users table */
        UPDATE users
        SET
            status = 'active',
            level = 3
        WHERE id = v_user_id;

        /* Update artist_profiles table */
        UPDATE artist_profiles
        SET
            artist_level = 3,
            is_active = 1
        WHERE user_id = v_user_id;

    COMMIT;
END$$

CREATE DEFINER=`u888578780_bbm`@`127.0.0.1` PROCEDURE `Artist by ID` (IN `p_user_id` INT)   BEGIN

    SELECT 
        u.id AS user_id,
        u.username,

        ap.business_name,
        ap.contact_person_name,
        ap.whatsapp_number,
        ap.artist_level,
        ap.is_active,

        sh.plan_name,
        sh.subscription_type,
        sh.start_date,
        sh.end_date,
        sh.status AS subscription_status

    FROM users u

    LEFT JOIN artist_profiles ap 
        ON ap.user_id = u.id

    LEFT JOIN subscription_history sh
        ON sh.user_id = u.id
        AND sh.status = 'active'   -- current active plan only

    WHERE u.id = p_user_id;

END$$

CREATE DEFINER=`u888578780_bbm`@`127.0.0.1` PROCEDURE `Artist Claims Daywise` (IN `p_username` VARCHAR(100))   BEGIN
    DECLARE v_user_id INT;

    /* Fetch user_id from username */
    SELECT id
    INTO v_user_id
    FROM users
    WHERE username = p_username
    LIMIT 1;

    /* Safety check */
    IF v_user_id IS NULL THEN
        SIGNAL SQLSTATE '45000'
        SET MESSAGE_TEXT = 'User not found';
    END IF;

    /* Day-wise claim count in IST */
    SELECT
        DATE(CONVERT_TZ(cll.claim_time, '+00:00', '+05:30')) AS claim_date,
        COUNT(*) AS total_claims
    FROM claimed_leads_log cll
    WHERE cll.user_id = v_user_id
    GROUP BY claim_date
    ORDER BY claim_date DESC;

END$$

CREATE DEFINER=`u888578780_bbm`@`127.0.0.1` PROCEDURE `Claim Order` ()   BEGIN
    SELECT
        cll.id AS claim_id,
        /* cll.created_at AS claimed_at, */
        
        /* Convert UTC → IST */
        CONVERT_TZ(cll.created_at, '+00:00', '+05:30') AS claimed_at,
        l.customer_name AS lead_name,
        l.location AS Place,
       

        /* Claim order for the SAME lead (1st / 2nd) */
        ROW_NUMBER() OVER (
            PARTITION BY cll.lead_id
            ORDER BY cll.id
        ) AS order_c,

        ap.contact_person_name AS artist_name,
/* 3️⃣ Artist DAILY claim count (IST-based) */
        ROW_NUMBER() OVER (
            PARTITION BY 
                cll.user_id,
                DATE(CONVERT_TZ(cll.created_at, '+00:00', '+05:30'))
            ORDER BY cll.id
        ) AS Day_Count,

        /* Artist’s running claim count */
        ROW_NUMBER() OVER (
            PARTITION BY cll.user_id
            ORDER BY cll.id
        ) AS Total_Count,
        ap.business_name

    FROM claimed_leads_log cll
    INNER JOIN leads l
        ON cll.lead_id = l.id
    INNER JOIN artist_profiles ap
        ON cll.user_id = ap.user_id
    ORDER BY cll.id DESC;
END$$

CREATE DEFINER=`u888578780_bbm`@`127.0.0.1` PROCEDURE `Deactivate Artist` (IN `p_username` VARCHAR(255))   BEGIN
    DECLARE v_user_id INT DEFAULT NULL;

    /* Get user_id from username */
    SELECT id
    INTO v_user_id
    FROM users
    WHERE username = p_username
    LIMIT 1;

    /* Safety check */
    IF v_user_id IS NULL THEN
        SIGNAL SQLSTATE '45000'
        SET MESSAGE_TEXT = 'User not found';
    END IF;

    START TRANSACTION;

        /* Update users table */
        UPDATE users
        SET
            status = 'inactive',
            level = 5
        WHERE id = v_user_id;

        /* Update artist_profiles table */
        UPDATE artist_profiles
        SET
            artist_level = 5,
            is_active = 0
        WHERE user_id = v_user_id;

    COMMIT;
END$$

CREATE DEFINER=`u888578780_bbm`@`127.0.0.1` PROCEDURE `deactivate_user` (IN `p_user_id` INT)   BEGIN

  -- Update users table
  UPDATE users
  SET 
    status = 'inactive',
    level = 5
  WHERE id = p_user_id;

  -- Update artist_profiles
  UPDATE artist_profiles
  SET 
    is_active = 0,
    artist_level = 5
  WHERE user_id = p_user_id;
  
  -- Expire subscription history
  UPDATE subscription_history
  SET status = 'expired'
  WHERE user_id = p_user_id
    AND status = 'active';

END$$

CREATE DEFINER=`u888578780_bbm`@`127.0.0.1` PROCEDURE `get_artist_lead_claim_counts` ()   BEGIN
    SELECT
        ap.user_id,
        ap.whatsapp_number,
        ap.business_name,
        ap.contact_person_name,
        COUNT(cll.id) AS total_leads_claimed
    FROM artist_profiles ap
    LEFT JOIN claimed_leads_log cll
        ON cll.user_id = ap.user_id
     WHERE ap.is_active = 1
    GROUP BY
        ap.user_id,
        ap.business_name,
        ap.contact_person_name
    ORDER BY total_leads_claimed DESC;
END$$

CREATE DEFINER=`u888578780_bbm`@`127.0.0.1` PROCEDURE `get_daily_leads` ()   BEGIN
    SELECT 
        DATE(CONVERT_TZ(created_at, '+00:00', '+05:30')) AS lead_date,
        COUNT(*) AS total_leads
    FROM leads
    GROUP BY DATE(CONVERT_TZ(created_at, '+00:00', '+05:30'))
    ORDER BY lead_date DESC;
END$$

CREATE DEFINER=`u888578780_bbm`@`127.0.0.1` PROCEDURE `get_leads_by_date_and_source` (IN `p_ist_date` DATE, IN `p_lead_source` VARCHAR(100))   BEGIN
    SELECT id,lead_source, customer_name, whatsapp_number, event_date,event_type,services_required,location
    FROM leads
    WHERE DATE(CONVERT_TZ(created_at, '+00:00', '+05:30')) = p_ist_date
      AND lead_source = p_lead_source
    ORDER BY created_at DESC;
END$$

CREATE DEFINER=`u888578780_bbm`@`127.0.0.1` PROCEDURE `get_users_daywise_ist` ()   BEGIN
    SELECT 
        DATE(CONVERT_TZ(created_at, '+00:00', '+05:30')) AS day_wise,
        COUNT(id) AS total_users
    FROM users
    GROUP BY day_wise
    ORDER BY day_wise DESC;
END$$

DELIMITER ;

