DELIMITER $$
CREATE TRIGGER `auto_create_lead_tracking` AFTER INSERT ON `leads` FOR EACH ROW BEGIN
    -- Auto-create tracking record for new leads
        lead_id,
        current_status_id,
        team_member_id,
        created_by,
        is_claimed,
        service_type,
        created_at,
        updated_at
    ) VALUES (
        NEW.id,                    -- Use the new lead's ID
        1,                         -- Default status: "New" (status_id = 1)
        NULL,                      -- No team member assigned yet
        1,                         -- Created by admin/team_id = 1
        0,                         -- Not claimed yet (is_claimed = 0)
        NEW.services_required,     -- Use the service type from leads table
        NEW.created_at,            -- Use the lead's creation date
        NOW()                      -- Set updated_at to now
    );
END
$$
DELIMITER ;

