--
-- Triggers `users`
--
DELIMITER $$
CREATE TRIGGER `before_user_update` AFTER UPDATE ON `users` FOR EACH ROW BEGIN

  IF (OLD.status <> NEW.status) OR (OLD.level <> NEW.level) THEN

    UPDATE artist_profiles
    SET 
      is_active = CASE 
        WHEN NEW.status = 'active' THEN 1
        ELSE 0
      END,
      artist_level = NEW.level
    WHERE user_id = NEW.id;

  END IF;

END
$$
DELIMITER ;

